CREATE TABLE public.pending_deletions (id BIGSERIAL PRIMARY KEY, chat_id BIGINT NOT NULL, message_id BIGINT NOT NULL, delete_at TIMESTAMPTZ NOT NULL, created_at TIMESTAMPTZ NOT NULL DEFAULT now()); CREATE INDEX idx_pending_deletions_delete_at ON public.pending_deletions(delete_at); GRANT ALL ON public.pending_deletions TO service_role; GRANT USAGE, SELECT ON SEQUENCE public.pending_deletions_id_seq TO service_role; ALTER TABLE public.pending_deletions ENABLE ROW LEVEL SECURITY;